#### Phase 5: Layer Components

**File: `client/src/components/Universe/layers/DeepSpaceLayer.jsx`** (new)

```jsx
import { memo, useMemo } from 'react';
import { Layer, Circle } from 'react-konva';
import { generateDeepSpaceStars, generateNebulae } from '../utils/proceduralGeneration';
import Nebula from '../components/Nebula';

const DeepSpaceLayer = memo(({ layerProps }) => {
    // Generated once, never changes (deterministic seed)
    const stars = useMemo(() => generateDeepSpaceStars(2000, 42), []);
    const nebulae = useMemo(() => generateNebulae(18, 256), []);

    return (
        <Layer {...layerProps} listening={false}>
            {/* Nebulae (behind dust stars) */}
            {nebulae.map((n, i) => (
                <Nebula key={`neb-${i}`} {...n} />
            ))}
            {/* Dust stars */}
            {stars.map((s, i) => (
                <Circle
                    key={`ds-${i}`}
                    x={s.x}
                    y={s.y}
                    radius={s.radius}
                    fill={s.color}
                    perfectDrawEnabled={false}
                    listening={false}
                />
            ))}
        </Layer>
    );
});

DeepSpaceLayer.displayName = 'DeepSpaceLayer';
export default DeepSpaceLayer;
```

**Performance consideration for 2000 + 72 shapes (18 nebulae * 4 circles each):** These are all static and `listening={false}`. Konva's Layer will batch-draw them. The layer never re-renders because `layerProps` only changes when camera/zoom changes, and `memo` + the stable `useMemo` arrays mean no internal re-creation.

However, 2000 individual `<Circle>` React elements is a lot of React reconciliation overhead. To optimize further, consider using a single `<Shape>` with a custom `sceneFunc` that draws all dust stars in one pass:

```jsx
import { Shape } from 'react-konva';

const DustStarsShape = memo(({ stars }) => (
    <Shape
        sceneFunc={(ctx) => {
            for (const s of stars) {
                ctx.beginPath();
                ctx.arc(s.x, s.y, s.radius, 0, Math.PI * 2);
                ctx.fillStyle = s.color;
                ctx.fill();
            }
        }}
        listening={false}
        perfectDrawEnabled={false}
    />
));
```

This reduces 2000 React elements to 1, with 2000 native canvas draw calls. Much faster reconciliation. **Recommendation: Use this `<Shape>` approach for both deep space and mid-galaxy static stars.**

**File: `client/src/components/Universe/layers/MidGalaxyLayer.jsx`** (new)

```jsx
import { memo, useMemo } from 'react';
import { Layer, Shape } from 'react-konva';
import { generateMidGalaxyStars } from '../utils/proceduralGeneration';
import { hexToRgba } from '../utils/starUtils';

const MidGalaxyLayer = memo(({ layerProps }) => {
    const stars = useMemo(() => generateMidGalaxyStars(800, 137), []);

    return (
        <Layer {...layerProps} listening={false}>
            <Shape
                sceneFunc={(ctx) => {
                    for (const s of stars) {
                        ctx.beginPath();
                        ctx.arc(s.x, s.y, s.radius, 0, Math.PI * 2);
                        // Create a radial gradient for each mid-galaxy star
                        const grad = ctx.createRadialGradient(
                            s.x, s.y, 0,
                            s.x, s.y, s.radius
                        );
                        grad.addColorStop(0, hexToRgba(s.color, s.opacity));
                        grad.addColorStop(1, hexToRgba(s.color, 0));
                        ctx.fillStyle = grad;
                        ctx.fill();
                    }
                }}
                listening={false}
                perfectDrawEnabled={false}
            />
        </Layer>
    );
});

MidGalaxyLayer.displayName = 'MidGalaxyLayer';
export default MidGalaxyLayer;
```

